  ('diplomatic-535efab1-moex-00628', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-110-e6f33b51', 'sub-diplomatic-535efab1-03', NULL, 'single_choice', '下列何者屬於非關稅壁壘的措施？', '["中央銀行的貨幣政策", "政府採購政策", "匯率政策", "財政政策"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:37+00:00", "source_pdf_sha1": "ab8dabb335f2", "answer_pdf_sha1": "f7c4ac93c413", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際經濟", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00629', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-110-e6f33b51', 'sub-diplomatic-535efab1-03', NULL, 'single_choice', '根據產品生命週期（productlifecycle）模型，對比較利益的敘述，下列何者正確？', '["當產品的發展已成熟，比較利益將可能由原產品發明國轉移至其他國家", "對農產品或同質的工業產品而言，比較利益與這些產品所處的生命週期階段有關", "不論產品所處生命週期為何，原發明國將持續保有比較利益的地位", "比較利益與一國所擁有的技術勞動資源與研究發展產品的能力有關"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:37+00:00", "source_pdf_sha1": "ab8dabb335f2", "answer_pdf_sha1": "f7c4ac93c413", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際經濟", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00630', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-110-e6f33b51', 'sub-diplomatic-535efab1-03', NULL, 'single_choice', '因加入區域貿易組織，使一國減少與非會員國之貿易，改偏向會員國進行貿易之現象稱為：', '["貿易轉移（tradediversion）", "貿易扭曲（tradedistortion）", "貿易排除（tradeexclusion）", "貿易創造（tradecreation）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:37+00:00", "source_pdf_sha1": "ab8dabb335f2", "answer_pdf_sha1": "f7c4ac93c413", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際經濟", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00631', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-110-e6f33b51', 'sub-diplomatic-535efab1-03', NULL, 'single_choice', '為避免外國競爭對本國產業之不公平與不利影響，發展中國家應該扶植其正處於發展階段的產 業，此論點為：', '["免責條款假說", "制度性公平貿易政策", "保護國內市場", "幼稚產業觀點"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:37+00:00", "source_pdf_sha1": "ab8dabb335f2", "answer_pdf_sha1": "f7c4ac93c413", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際經濟", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00632', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-110-e6f33b51', 'sub-diplomatic-535efab1-03', NULL, 'single_choice', '若一國中央銀行不樂見該國貨幣之價值相對於其他貨幣上升，將會採行  ①  貨幣政策，以  ②  該 國國內利率水準，使該國貨幣趨於弱勢。', '["", "緊縮性", "降低", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:37+00:00", "source_pdf_sha1": "ab8dabb335f2", "answer_pdf_sha1": "f7c4ac93c413", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際經濟", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00633', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-110-e6f33b51', 'sub-diplomatic-535efab1-03', NULL, 'single_choice', '若某投資人手中未持有歐元，但預期歐元在爾後三個月內的價值將持續下滑。在該投資人預期正 確下，投資人採下列何種操作，將可以出現獲利？', '["買空歐元", "賣空歐元", "賣空美元", "作多歐元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:37+00:00", "source_pdf_sha1": "ab8dabb335f2", "answer_pdf_sha1": "f7c4ac93c413", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際經濟", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00634', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-110-e6f33b51', 'sub-diplomatic-535efab1-03', NULL, 'single_choice', '有關形成J曲線的原因，下列敘述何者正確？', '["因短期內供給高於需求，供給與需求在長期方達到相等所致", "因大眾隨新訊息進行調整，而出現的過度反應現象", "因投資人過度謹慎選擇外幣交易工具之行為所致", "相較於長期，因短期內商品之供給與需求較不具有彈性所致"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:37+00:00", "source_pdf_sha1": "ab8dabb335f2", "answer_pdf_sha1": "f7c4ac93c413", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際經濟", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00635', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-110-e6f33b51', 'sub-diplomatic-535efab1-03', NULL, 'single_choice', '在固定匯率與資本完全移動下，有關總體經濟政策效果的敘述，下列何者正確？', '["貨幣政策具超級有效性", "與貨幣政策相比，財政政策的效果較差", "財政政策無效", "貨幣政策無效"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:37+00:00", "source_pdf_sha1": "ab8dabb335f2", "answer_pdf_sha1": "f7c4ac93c413", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際經濟", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL)
